"""System tray icon using pystray with PIL-generated icon image."""

import logging
from typing import Any, Callable

from PIL import Image, ImageDraw

logger = logging.getLogger(__name__)

TRAY_ICON_SIZE = (64, 64)
TRAY_ICON_NAME = "Claude Dashboard"
_DEFAULT_COLOR = (128, 128, 128)  # Gray


def generate_icon_image(
    *,
    color: tuple[int, int, int] = _DEFAULT_COLOR,
    pupil_color: tuple[int, int, int] = (20, 20, 20),
) -> Image.Image:
    """Generate a PIL Image for the tray icon — off-center eye.

    An asymmetric eye shape looking slightly to the right. Solid state
    color fill, transparent background. The off-center pupil gives it
    personality — 'keeping an eye on your sessions'.
    """
    size = TRAY_ICON_SIZE[0]
    scale = 4
    hi = size * scale
    image = Image.new("RGBA", (hi, hi), (0, 0, 0, 0))
    draw = ImageDraw.Draw(image)

    cx, cy = hi // 2, hi // 2
    margin = 3 * scale

    # --- Outer eye (filled circle with black outline) ---
    # Black outline prevents system tray downscaling from blending
    # the state color into the background as visible green artifacts.
    outline_w = scale
    draw.ellipse(
        [margin, margin, hi - margin, hi - margin],
        fill=color,
        outline=(0, 0, 0),
        width=outline_w,
    )

    # --- Iris/pupil (dark circle, offset right and slightly up) ---
    pupil_r = 10 * scale
    pupil_cx = cx + 6 * scale
    pupil_cy = cy - 2 * scale
    draw.ellipse(
        [pupil_cx - pupil_r, pupil_cy - pupil_r, pupil_cx + pupil_r, pupil_cy + pupil_r],
        fill=pupil_color,
    )

    result = image.resize((size, size), Image.Resampling.LANCZOS)
    # Threshold alpha to eliminate semi-transparent edge pixels that
    # appear as colored glow on dark tray backgrounds.
    alpha = result.getchannel("A").point(lambda a: 255 if a > 128 else 0)
    result.putalpha(alpha)
    return result


def create_tray_icon(
    *,
    on_toggle: Callable,
) -> Any:
    """Create and return a pystray Icon (not yet running).

    on_toggle is called on left-click to toggle dashboard visibility.
    No menu — on Linux/Wayland AppIndicator, menus are unreliable.
    """
    import pystray

    icon_image = generate_icon_image()

    icon = pystray.Icon(
        name=TRAY_ICON_NAME,
        icon=icon_image,
        title=TRAY_ICON_NAME,
        menu=pystray.Menu(
            pystray.MenuItem("Toggle", on_toggle, default=True, visible=False),
        ),
    )
    return icon


def update_tray_icon(
    icon: Any,
    *,
    color: tuple[int, int, int] = _DEFAULT_COLOR,
) -> None:
    """Update the tray icon color."""
    try:
        icon.icon = generate_icon_image(color=color)
    except Exception as exc:
        logger.debug("failed to update tray icon error=%s", exc)
